mpany.</p>\n<p style="text-align: justify;">I accept all the terms and conditions mentioned therein. I shall commence my probation with effect from __________________<br><br></p>\n<p style="text-align: justify;">&nbsp;</p>\n<p style="text-align: justify;">Name:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Date:&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Signature:</p>	/uploads/pdfs/offer_1776770399428.pdf	f	2026-04-21 11:19:59.902	\N	{"ctc": 500000, "dob": "", "hra": 98112.31898277148, "pan": "", "city": "", "date": "", "grat": 9438.405086142615, "mode": "Office", "name": "Mr. poorna", "spec": 177024.637965543, "basic": 196224.637965543, "email": "m@fingrow.in", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "40", "exitType": "Resigned", "lastName": "", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "poorna", "incAmount": "", "offerDate": "", "transport": 19200, "currentCtc": "", "deductions": "0", "department": "Operations", "exitReason": "", "fatherName": "", "revisedCtc": "500000", "assetReturn": "Completed", "designation": "Software Engineer", "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "", "offerExpiry": "", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "lastWorkingDay": "", "probationStart": "", "sigDesignation": "HR Man