sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1776840224625.pdf	f	2026-04-22 06:43:44.774	\N	{"ctc": 50000, "dob": "", "hra": 9811.23189827715, "pan": "", "city": "", "date": "", "grat": 943.8405086142617, "mode": "Office", "name": "Mr. poorna", "spec": 422.4637965542961, "basic": 19622.4637965543, "email": "m@gmail.com", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "pooo", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "poorna", "incAmount": "", "offerDate": "2026-04-21", "transport": 19200, "validTill": "2026-04-23", "currentCtc": "", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "revisedCtc": "50000", "assetReturn": "Completed", "designation": "Associate Engineers", "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "2026-04-23", "offerExpiry": "2026-04-23", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "lastWorkingDay": "", "probationStart": "", "sigDesignation": "HR Manager", "leaveEncashment": "0", "probationPeriod": "3", "resignationDate