sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1776841560237.pdf	f	2026-04-22 07:06:00.375	\N	{"ctc": 0, "dob": "2026-04-23", "hra": 0, "pan": "", "city": "", "date": "", "grat": 0, "mode": "Office", "name": "Mr. poorna", "spec": 0, "basic": 0, "email": "m@gmail.com", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Internship", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "poorna", "incAmount": "", "offerDate": "", "transport": 19200, "validTill": "", "currentCtc": "", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "revisedCtc": "", "assetReturn": "Completed", "designation": "Associate Engineers", "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "", "offerExpiry": "", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "2026-04-23", "lastWorkingDay": "", "probationStart": "", "sigDesignation": "HR Manager", "internshipStart": "2026-08-21", "leaveEncashment": "0", "probationPeriod": "6", "resignationDate": "", "revisedCtcOffer": "", "noticePay