eturn all company property and that the property will be returned in proper working order. I understand I may be held financially responsible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1777368741733.pdf	f	2026-04-28 09:32:22.338	cmoiesezp0000zaah9tn63l93	{"ctc": 467890, "dob": "", "pan": "", "city": "", "date": "2026-04-16", "grat": 8806.67375691692, "mode": "Office", "name": "Mr. mpc m", "spec": 183090.9304972332, "basic": 183090.9304972333, "email": "m45@gmail.com", "state": "Karnataka", "gender": "Male", "hraPct": "50", "mobile": "123450", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "Karnataka", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "fghj", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "mpc m", "location": "bangalore", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Mr.", "incAmount": "", "includePT": "No", "manualEpf": "56", "manualEsi": "57", "offerDate": "2026-04-29", "validTill": "2026-04-30", "currentCtc": "", "deductions": "0", "department": "Marketing", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "revisedCtc": "467890", "assetReturn": "Completed", "designation": "software engineering", "epfEmployee": 56, "esiEmployee": 57, "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "2026-04-23", "offerExpiry": "2026-04-30", "reviewNotes": "", "monthlyGross": 38143.9438