sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1776935270041.pdf	f	2026-04-23 09:07:52.449	cmob91a2v000f2u0i6hildsgz	{"ctc": 450000, "dob": "", "pan": "", "city": "", "date": "", "grat": 12597.20062208398, "mode": "Office", "name": "Mr. Ms. poorna chandrika", "spec": 57387.24727838262, "basic": 262441.6796267496, "email": "", "state": "", "gender": "Male", "hraPct": "40", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "60", "duration": "3", "exitType": "Resigned", "lastName": "poorna chandrika", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Ms.", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "revisedCtc": "450000", "assetReturn": "Completed", "designation": "", "finalAmount": "0", "gratuityPct": "4.8", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "2026-04-08", "offerExpiry": "", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "", "lastWorkingDay": "", "probationStart": "", "sigDesignation": "HR Manager", "internshipStart": "", "leaveEncashment": "0", "pr