sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1776936551959.pdf	f	2026-04-23 09:29:12.336	cmob9sq0m0002ior3f5y46o7d	{"ctc": 500000, "dob": "", "pan": "", "city": "", "date": "", "grat": 13996.88958009331, "mode": "Office", "name": "Mr. Mr. poorna m189", "spec": 34603.42146189739, "basic": 291601.866251944, "email": "", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "60", "duration": "3", "exitType": "Resigned", "lastName": "poorna m189", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Mr.", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "revisedCtc": "500000", "assetReturn": "Completed", "designation": "", "finalAmount": "0", "gratuityPct": "4.8", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "", "offerExpiry": "", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "", "lastWorkingDay": "", "probationStart": "", "sigDesignation": "HR Manager", "internshipStart": "", "leaveEncashment": "0", "probationPeriod": "6", 