sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1777009464517.pdf	f	2026-04-24 05:44:25.007	cmochjy4700008zc9msds3ugj	{"ctc": 300000, "dob": "", "pan": "", "city": "", "date": "", "grat": 8398.133748055989, "mode": "Office", "name": "Mr.", "spec": 20762.0528771384, "basic": 174961.1197511664, "email": "m3@gmail.com", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "45", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "", "manualPt": "50", "passport": "", "reviewer": "", "altMobile": "", "firstName": "", "incAmount": "", "includePT": "Yes", "manualEpf": "1000", "manualEsi": "12", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "ptOverride": "50", "revisedCtc": "300000", "assetReturn": "Completed", "designation": "Software Engineer", "finalAmount": "0", "gratuityPct": "3.5", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "2026-04-01", "offerExpiry": "", "reviewNotes": "", "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "", "lastWorkingDay": "", "probationStart": "", "sig