sible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1777368030994.pdf	f	2026-04-28 09:20:32.106	cmoidp4kr0000493du0aohpp4	{"ctc": 3456790, "dob": "", "pan": "", "city": "", "date": "2026-04-16", "grat": 65253.16863545388, "mode": "Office", "name": "jzx", "spec": 1356614.732545818, "basic": 1356614.732545819, "email": "m7@gmail.com", "state": "Andhra Pradesh", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "Andhra Pradesh", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "harish", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "Tirupati", "passport": "", "reviewer": "", "altMobile": "", "firstName": "jzx", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "HR", "exitReason": "", "fatherName": "", "includeEPF": "No", "includeESI": "No", "revisedCtc": "3456790", "assetReturn": "Completed", "designation": "HR Manager", "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "2026-04-24", "offerExpiry": "", "reviewNotes": "", "monthlyGross": 282628.0692803789, "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "Tirupati", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "", "lastWorkingDay": "", "probationStart": "",