cmobaq0eq0009kv11c0mr8fx2	\N	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp; &nbsp;</p>\n<p><strong>-effective from- </strong>.For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1776937523359.pdf	f	2026-04-23 09:45:23.845	\N	{"ctc": 56789, "dob": "", "pan": "", "city": "", "date": "", "grat": 1589.738724727838, "mode": "Office", "name": "Mr. Ms. poorna chandrika", "spec": 3930.187402799376, "basic": 33119.5567651633, "email": "hired_emp003@fingrow.in", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "50", "duration": "3", "exitType": "Resigned", "lastName": "poorna chandrika", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Ms.", "incAmount": "33333", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "23456", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "revisedCtc": "56789", "assetReturn": "Completed", "designation