cmocvadqc000110t3dpczfxx8	\N	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp; &nbsp;</p>\n<p><strong>-effective from- </strong>.For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1777032532338.pdf	f	2026-04-24 12:08:52.737	\N	{"ctc": 688998, "dob": "", "pan": "", "city": "", "date": "", "grat": 13006.08445508418, "mode": "Office", "name": "Mr. Mr. merr jhgh", "spec": 270396.7662179663, "basic": 270396.7662179663, "email": "m2@gmail.com", "state": "Andhra Pradesh", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "Andhra Pradesh", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "merr jhgh", "location": "Tirupati", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Mr.", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes", "revisedCtc": "688998", "assetReturn": "Completed", "designa