cmogslfqa0005p15o9gebfhtl	cmo9zwvcb000912gpb5g076tj	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp; &nbsp;</p>\n<p><strong>-effective from- </strong>.For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1777269874040.pdf	f	2026-04-27 06:04:34.398	\N	{"ctc": 500000, "dob": "", "pan": "", "city": "", "date": "", "grat": 9913.809990205682, "mode": "Office", "name": "Mr. poorna", "spec": 75533.7904015671, "basic": 283251.7140058766, "email": "m@fingrow.in", "state": "", "gender": "Male", "hraPct": "40", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "60", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "", "manualPt": "200", "passport": "", "ptAmount": 200, "reviewer": "", "altMobile": "", "firstName": "poorna", "incAmount": "150000", "includePT": "Yes", "manualEpf": "1200", "manualEsi": "300", "offerDate": "", "validTill": "", "currentCtc": "350000", "deductions": "0", "department": "Management", "exitReason": "", "fatherName": "", "includeEPF": "Yes", "includeESI": "Yes"