cmo9x578t0009u0wa2r2zuzgj	\N	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp; &nbsp;</p>\n<p><strong>-effective from- </strong>.For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1776854251517.pdf	f	2026-04-22 10:37:31.753	\N	{"ctc": 679057, "dob": "", "hra": 133247.7139829677, "pan": "", "city": "", "date": "", "grat": 12818.43008516149, "mode": "Office", "name": "Mr. poorna", "spec": 247295.4279659354, "basic": 266495.4279659354, "email": "m@fingrow.in", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "poorna", "incAmount": "", "offerDate": "", "transport": 19200, "validTill": "", "currentCtc": "", "deductions": "0", "department": "Engineering", "exitReason": "", "fatherName": "", "revisedCtc": "679057", "assetReturn": "Completed", "designation": "Associate Engineers", "finalAmount": "0", "gratuityPct":