cmoh1d4xn000313fayrvtu49h	\N	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp; &nbsp;</p>\n<p><strong>-effective from- </strong>.For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1777284603505.pdf	f	2026-04-27 10:10:03.703	\N	{"ctc": 700000, "dob": "", "pan": "", "city": "", "date": "2026-04-30", "grat": 24324.32432432432, "mode": "Office", "name": "Mr. Mr. mp", "spec": 67567.56756756763, "basic": 405405.4054054053, "email": "m3@gmail.com", "state": "Andhra Pradesh", "gender": "Male", "hraPct": "50", "mobile": "234567800", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "Andhra Pradesh", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "", "sigName": "harish", "address1": "", "address2": "", "basicPct": "60", "duration": "3", "exitType": "Resigned", "lastName": "mp", "location": "Tirupati", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Mr.", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "Engineers", "exitReason": "", "fatherName": "", "includeEPF": "No", "includeESI": "No", "revisedCtc": "700000", "assetReturn": "Completed", "