cmojnpbyn0009m9r7u9vh8sx7	\N	INCREMENT	<!-- x-tinymce/html --><p>We extend our sincere appreciation for your commendable performance during the evaluation period. Your dedication and exceptional contributions have significantly impacted the success of our organization.</p>\n<p>In recognition of your hard work and commitment, we are pleased to inform you that your compensation will be increased to&nbsp;&nbsp;<strong>-CTC-</strong>. This revised annual remuneration will be effective from&nbsp;<strong style="font-size: 0.875rem;">-effective from- </strong><span style="font-size: 0.875rem;">.</span></p><p><span style="font-size: 0.875rem;">For a detailed breakdown of your revised compensation structure, please refer to Annexure-III.</span></p>\n<p>It is important to note that all other terms and conditions outlined in your Offer Letter will remain unchanged.</p>\n<p>Congratulations on your well-deserved success! We look forward to witnessing more exemplary work from you in the future. Your continued dedication and contributions are invaluable to the success of our organization.</p>	/uploads/pdfs/increment_1777443056267.pdf	f	2026-04-29 06:10:56.587	\N	{"ctc": 700000, "dob": "", "pan": "", "city": "tpt", "date": "2026-04-23", "grat": 12794.70193477493, "mode": "Office", "name": "mpc  mp", "spec": 266002.11922609, "basic": 266002.1192260901, "email": "m3@gmail.com", "empId": "", "state": "Andhra Pradesh", "gender": "Male", "hraPct": "50", "mobile": "12345678", "prefix": "Mr.", "reason": "", "refNum": "0019", "aadhaar": "", "address": "tpt, Andhra Pradesh, 234567", "contact": "m3@gmail.com", "country": "India", "empType": "Full-time", "manager": "", "pinCode": "234567", "sigName": "ha", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": " mp", "location": "Tirupati", "passport": "", "reviewer": "", "altMobile": "", "firstName": "mpc", "incAmount": "100000", "includePT": "No", "manualEpf": "1600", "manualEsi": "250", "offe