turn all company property and that the property will be returned in proper working order. I understand I may be held financially responsible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:	/uploads/pdfs/offer_1777370287133.pdf	f	2026-04-28 09:58:07.296	cmoidp4kr0000493du0aohpp4	{"ctc": 0, "dob": "", "pan": "", "city": "", "date": "", "grat": 0, "mode": "Remote", "name": "Mr. fghj", "spec": 0, "basic": 0, "email": "m7@gmail.com", "state": "", "gender": "Male", "hraPct": "50", "mobile": "", "prefix": "Mr.", "reason": "", "aadhaar": "", "address": "", "country": "India", "empType": "Internship", "manager": "", "pinCode": "", "sigName": "", "address1": "", "address2": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "fghj", "location": "", "passport": "", "reviewer": "", "altMobile": "", "firstName": "Mr.", "incAmount": "", "includePT": "No", "offerDate": "", "validTill": "", "currentCtc": "", "deductions": "0", "department": "", "exitReason": "", "fatherName": "", "includeEPF": "No", "includeESI": "No", "revisedCtc": "", "assetReturn": "Completed", "designation": "software engineering", "finalAmount": "0", "gratuityPct": "4.81", "hrClearance": "Yes", "itClearance": "Yes", "joiningDate": "", "offerExpiry": "", "reviewNotes": "", "monthlyGross": 0, "noticePeriod": "30", "noticeServed": "Yes", "probationEnd": "", "workLocation": "", "confirmStatus": "Confirmed", "effectiveDate": "", "incPercentage": "", "incrementType": "Annual", "internshipEnd": "2026-04-22", "lastWorkingDay": "", "prob