return all company property and that the property will be returned in proper working order. I understand I may be held financially responsible for lost or damaged property. This agreement includes, but is not limited to, laptops, cell phones and other equipment. I understand that failure to return equipment will be considered theft and may lead to criminal prosecution by Company.\n\nI accept all the terms and conditions mentioned therein. I shall commence my Internship with effect from __________________\n\nName:                                                                             Date:                                                Signature:</div>	/uploads/pdfs/offer_1777452237046.pdf	f	2026-04-29 08:43:57.499	cmojt63lm0000w2nhbh074aad	{"ctc": 540000, "dob": "2002-05-18", "pan": "", "uan": "", "city": "tpt", "date": "2026-04-23", "grat": 10389.6, "ifsc": "", "mode": "Office", "name": "poorna manikyam", "spec": 216000, "basic": 216000, "email": "m78@gmail.com", "empId": "", "state": "Andhra Pradesh", "gender": "Male", "hraPct": "50", "mobile": "123456780", "prefix": "Mr.", "reason": "", "refNum": "0025", "aadhaar": "", "address": "tpt, Andhra Pradesh, 4356", "contact": "m78@gmail.com", "country": "India", "empType": "Internship", "manager": "", "pinCode": "4356", "sigName": "harsih", "address1": "", "address2": "", "bankName": "", "basicPct": "40", "duration": "3", "exitType": "Resigned", "lastName": "manikyam", "location": "Tirupati", "passport": "", "pfNumber": "", "reviewer": "", "accountNo": "", "altMobile": "", "firstName": "poorna", "incAmount": "", "includePT": "No", "offerDate": "2026-04-28", "validTill": "2026-04-30", "currentCtc": "", "deductions": "0", "department": "HR", "employeeId": null, "exitReason": "", "fatherName": "", "includeEPF": "No", "includeESI": "No", "revisedCtc": "45000", "assetReturn": "Completed", "candidateId": "cmojt63lm0000w2nhbh074aad", "designation": "software engineering", "finalAmount": "0", "gratuityPct": "4.81", "hrClea